function.body:
vRecord RECORD; BEGIN BEGIN SELECT * INTO vRecord FROM scrvro_distance_matrix WHERE salesrep_id=vSalesRepId AND bpartner_from=vbPartnerFromId AND type_route=vTypeRoute ORDER BY duration ASC LIMIT 1;
INSERT INTO scrvro_optimized_route ( scrvro_optimized_route_id, ad_client_id, ad_org_id, createdby, updatedby, salesrep_id, c_bpartner_id, latitude, longitude, destination_addresses, distance, duration, visit_order, type_route ) VALUES ( get_uuid(), vRecord.ad_client_id, vRecord.ad_org_id, vRecord.createdby, vRecord.updatedby, vSalesRepId, vRecord.bpartner_to, vRecord.latitude, vRecord.longitude, vRecord.destination_addresses, vRecord.distance, vRecord.duration, (SELECT COALESCE(MAX(visit_order),0)+1 FROM scrvro_optimized_route WHERE salesrep_id=vSalesRepId AND type_route=vTypeRoute), vTypeRoute );
RETURN vRecord.bpartner_to; END; EXCEPTION WHEN OTHERS THEN RETURN SQLERRM; END SCRVRO_NEAREST_POINT
